#include<bits/stdc++.h>
using namespace std;
long long n,m,l;
void exgcd(long long &x,long long &y,long long a,long long b)
{
    if(b==0)
    {
        x=1;
        y=0;
        return;
    }
    long long x1,y1;
    exgcd(x1,y1,b,a%b);
    x=y1;
    y=x1-a/b*y1;
}
long long mul(long long x,long long y)
{
    long long sum=0;
    while(y)
    {
        if(y%2==1)
        {
            sum=(sum+x)%(n+1);
        }
        x=(x+x)%(n+1);
        y/=2;
    }
    return sum;
}
long long mypow(long long x,long long y)
{
    long long sum=1;
    while(y)
    {
        if(y%2==1)
        {
            sum=mul(sum,x)%(n+1);
        }
        x=mul(x,x)%(n+1);
        y/=2;
    }
    return sum;
}
int main()
{
    scanf("%lld%lld%lld",&n,&m,&l);
    long long a=mypow(2,m),b=n+1,x,y;
    exgcd(x,y,a,b);
    x=mul(x,l);
    printf("%lld",(x+(n+1))%(n+1));
    return 0;
}
